import{_ as d,o as a,c as e,ai as r}from"./chunks/framework.DyvBZb4W.js";const b=JSON.parse('{"title":"羁绊详情","description":"","frontmatter":{},"headers":[],"relativePath":"mods/xuanji-character/synergies.md","filePath":"mods/xuanji-character/synergies.md","lastUpdated":1780733792000}'),h={name:"mods/xuanji-character/synergies.md"};function l(i,t,n,s,o,g){return a(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="羁绊详情" tabindex="-1">羁绊详情 <a class="header-anchor" href="#羁绊详情" aria-label="Permalink to &quot;羁绊详情&quot;">​</a></h1><p>本页列出玄羁当前版本 <code>0.10.0-beta</code> 的羁绊阈值、主机核效果和各进度档效果。已按当前公开预览版本重新核对，数值以当前实现为准，后续 Beta 调整时可能变化。</p><h2 id="通用规则" tabindex="-1">通用规则 <a class="header-anchor" href="#通用规则" aria-label="Permalink to &quot;通用规则&quot;">​</a></h2><ul><li>带羁绊的牌纳编后进入机匣；机匣集齐 3 张牌时凝成机核。</li><li>单个机核内，同一种羁绊最多贡献 4 点。</li><li>机核主标签取贡献最高的羁绊；并列时，取机匣最早牌的第一个并列标签。</li><li>机盘最多保留 3 个机核；新机核会插到最左侧，超过上限时移除最右侧机核。</li><li>羁绊进度来自当前机盘中所有机核的贡献总和。协同金档后会提供额外有效进度，见下方“协同”。</li></ul><h2 id="固守" tabindex="-1">固守 <a class="header-anchor" href="#固守" aria-label="Permalink to &quot;固守&quot;">​</a></h2><p>主机核效果：每回合开始时，每个固守机核给予 3 点格挡。</p><table tabindex="0"><thead><tr><th>档位</th><th style="text-align:right;">进度</th><th>效果</th></tr></thead><tbody><tr><td>铜</td><td style="text-align:right;">2</td><td>每当你从自己的卡牌获得格挡时，额外获得 2 点格挡。</td></tr><tr><td>银</td><td style="text-align:right;">5</td><td>回合开始时，若你拥有任意机核，获得 6 点格挡。</td></tr><tr><td>金</td><td style="text-align:right;">8</td><td>格挡不再在你的回合开始时消失。</td></tr><tr><td>炫彩</td><td style="text-align:right;">11</td><td>受到攻击伤害后，把被格挡吸收的伤害等量反弹给攻击者。</td></tr></tbody></table><h2 id="突袭" tabindex="-1">突袭 <a class="header-anchor" href="#突袭" aria-label="Permalink to &quot;突袭&quot;">​</a></h2><p>主机核效果：每回合第一次打出攻击牌时，每个突袭机核对目标追加 3 点伤害。</p><table tabindex="0"><thead><tr><th>档位</th><th style="text-align:right;">进度</th><th>效果</th></tr></thead><tbody><tr><td>铜</td><td style="text-align:right;">3</td><td>回合开始时获得 3 点活力。</td></tr><tr><td>银</td><td style="text-align:right;">5</td><td>回合开始时改为获得 5 点活力。</td></tr><tr><td>金</td><td style="text-align:right;">8</td><td>回合开始时，本回合获得 6 点力量。</td></tr><tr><td>炫彩</td><td style="text-align:right;">12</td><td>回合开始时，将 1 张额外的突袭攻击牌加入手牌。</td></tr></tbody></table><h2 id="推演" tabindex="-1">推演 <a class="header-anchor" href="#推演" aria-label="Permalink to &quot;推演&quot;">​</a></h2><p>主机核效果：纳编时抽 1 张牌，每回合最多触发一次。</p><table tabindex="0"><thead><tr><th>档位</th><th style="text-align:right;">进度</th><th>效果</th></tr></thead><tbody><tr><td>铜</td><td style="text-align:right;">3</td><td>回合开始时抽 1 张牌。</td></tr><tr><td>银</td><td style="text-align:right;">6</td><td>每回合第一次纳编时，额外抽 1 张牌。</td></tr><tr><td>金</td><td style="text-align:right;">9</td><td>每次正常抽牌张数 +1；回合开始后可弃 1 张牌，并可选择最多 2 张手牌消耗；每回合第一次打出技能牌时抽 1 张牌。</td></tr><tr><td>炫彩</td><td style="text-align:right;">12</td><td>每当你抽到一张自己的牌时，对所有敌人造成 7 点伤害。</td></tr></tbody></table><h2 id="超载" tabindex="-1">超载 <a class="header-anchor" href="#超载" aria-label="Permalink to &quot;超载&quot;">​</a></h2><p>主机核效果：每回合第一次凝核后，每个超载机核获得 1 点能量。</p><table tabindex="0"><thead><tr><th>档位</th><th style="text-align:right;">进度</th><th>效果</th></tr></thead><tbody><tr><td>铜</td><td style="text-align:right;">3</td><td>每回合第一次凝核后，额外获得 1 点能量。</td></tr><tr><td>银</td><td style="text-align:right;">5</td><td>最大能量 +1。</td></tr><tr><td>金</td><td style="text-align:right;">8</td><td>未用完的能量会保留到下回合。</td></tr><tr><td>炫彩</td><td style="text-align:right;">11</td><td>回合开始时，按当前能量对所有敌人造成伤害：每点能量造成 15 点伤害。</td></tr></tbody></table><h2 id="蓄势" tabindex="-1">蓄势 <a class="header-anchor" href="#蓄势" aria-label="Permalink to &quot;蓄势&quot;">​</a></h2><p>主机核效果：回合结束时，若本回合没有凝核，每个蓄势机核获得 1 金币；每场战斗最多 12 金币。</p><table tabindex="0"><thead><tr><th>档位</th><th style="text-align:right;">进度</th><th>效果</th></tr></thead><tbody><tr><td>铜</td><td style="text-align:right;">3</td><td>回合结束时获得 2 金币；每场战斗最多 10 金币。</td></tr><tr><td>银</td><td style="text-align:right;">6</td><td>上述回合结束收益改为 8 金币；每场战斗最多 40 金币。</td></tr><tr><td>金</td><td style="text-align:right;">9</td><td>战斗胜利时获得 2 点最大生命。</td></tr><tr><td>炫彩</td><td style="text-align:right;">12</td><td>回合开始时，最多每场战斗 3 次，随机升级牌库中的一张可升级牌；若没有可升级牌，则给随机牌库牌添加 1 次重放。战斗胜利时获得或叠加蓄势纹章。</td></tr></tbody></table><p>蓄势纹章：战斗开始时，每层计数获得 1 点力量和 1 点敏捷。</p><h2 id="转化" tabindex="-1">转化 <a class="header-anchor" href="#转化" aria-label="Permalink to &quot;转化&quot;">​</a></h2><p>主机核效果：每回合第一次消耗自己的卡牌时，每个转化机核抽 1 张牌。</p><table tabindex="0"><thead><tr><th>档位</th><th style="text-align:right;">进度</th><th>效果</th></tr></thead><tbody><tr><td>铜</td><td style="text-align:right;">3</td><td>纳编时抽 1 张牌。</td></tr><tr><td>银</td><td style="text-align:right;">6</td><td>纳编时再抽 1 张牌，并选择 1 张手牌消耗。</td></tr><tr><td>金</td><td style="text-align:right;">9</td><td>每当消耗自己的卡牌时，获得 1 点能量。</td></tr><tr><td>炫彩</td><td style="text-align:right;">12</td><td>每当消耗自己的卡牌时，生成 1 张随机非基础牌加入手牌；若该牌不是 X 费，则本场战斗费用降为 0，并获得消耗。</td></tr></tbody></table><h2 id="蚀刻" tabindex="-1">蚀刻 <a class="header-anchor" href="#蚀刻" aria-label="Permalink to &quot;蚀刻&quot;">​</a></h2><p>主机核效果：每回合开始时，每个蚀刻机核给予生命最高的敌人 1 层中毒。</p><table tabindex="0"><thead><tr><th>档位</th><th style="text-align:right;">进度</th><th>效果</th></tr></thead><tbody><tr><td>铜</td><td style="text-align:right;">2</td><td>回合开始时，给予生命最高的敌人 1 层中毒和 1 层虚弱。</td></tr><tr><td>银</td><td style="text-align:right;">5</td><td>回合开始时，给予生命最低的敌人 1 层中毒和 1 层易伤。</td></tr><tr><td>金</td><td style="text-align:right;">8</td><td>回合开始时，给予所有敌人 1 层中毒、1 层虚弱和 1 层易伤。</td></tr><tr><td>炫彩</td><td style="text-align:right;">11</td><td>回合开始时，额外给予所有敌人 25 层中毒。</td></tr></tbody></table><h2 id="协同" tabindex="-1">协同 <a class="header-anchor" href="#协同" aria-label="Permalink to &quot;协同&quot;">​</a></h2><p>主机核效果：其他主机核效果触发时，每个协同机核获得 1 点格挡；每回合最多 3 次。</p><table tabindex="0"><thead><tr><th>档位</th><th style="text-align:right;">进度</th><th>效果</th></tr></thead><tbody><tr><td>铜</td><td style="text-align:right;">3</td><td>每当你凝核时，获得 5 点格挡。</td></tr><tr><td>银</td><td style="text-align:right;">6</td><td>其他羁绊触发时，获得 3 点格挡。</td></tr><tr><td>金</td><td style="text-align:right;">9</td><td>其他羁绊触发时，额外抽 1 张牌并获得 1 点能量；每回合最多 2 次。所有羁绊的有效进度 +1。</td></tr><tr><td>炫彩</td><td style="text-align:right;">12</td><td>所有羁绊进度额外 +3；其他羁绊触发时，对所有敌人造成 12 点伤害，并获得 20 点格挡。</td></tr></tbody></table><p>协同的进度加成会影响所有羁绊的有效进度显示与阈值判断；因此协同成型后，其他羁绊可能会被一起推到更高档位。</p><h2 id="链接" tabindex="-1">链接 <a class="header-anchor" href="#链接" aria-label="Permalink to &quot;链接&quot;">​</a></h2><ul><li>返回：<a href="/jasonsong-games/mods/xuanji-character/">玄羁 人物 Mod</a></li><li>查看：<a href="/jasonsong-games/mods/xuanji-character/faq">常见问题</a></li></ul>',32)])])}const y=d(h,[["render",l]]);export{b as __pageData,y as default};
